            byCode[LocaleCode.FromString("zh-Hans-HK")],
            byCode[LocaleCode.FromString("zh-Hans-MO")],
            byCode[LocaleCode.FromString("zh-Hans-MY")],
            byCode[LocaleCode.FromString("zh-Hans-SG")],
            byCode[LocaleCode.FromString("zh-Hant")],
            byCode[LocaleCode.FromString("zh-Hant-HK")],
            byCode[LocaleCode.FromString("zh-Hant-MO")],
            byCode[LocaleCode.FromString("zh-Hant-MY")],
            byCode[LocaleCode.FromString("zh-Hant-TW")],
            byCode[LocaleCode.FromString("zh-Latn")],
            byCode[LocaleCode.FromString("zu")],
            byCode[LocaleCode.FromString("zu-ZA")],
        };
        All = all;
    }

    /// <summary>
    /// Wire-nav step of the two-pass populate pattern. Invoked exactly
    /// once by <c>GeoDataInitializer</c> after every catalog's first-pass
    /// static ctor has run. Mutates each locale's <c>Language</c> +
    /// <c>Country</c> nav refs via the friend-assembly
    /// <c>internal set</c> accessors.
    /// </summary>
    internal static void WireNav()
    {
        foreach (var locale in All)
        {
            if (locale.LanguageIso6391Code is { } lc
                && LanguageLookup.ByCode.TryGetValue(lc, out var lang))
            {
                locale.Language = lang;
            }

            if (locale.CountryIso31661Alpha2Code is { } cc
                && CountryLookup.ByCode.TryGetValue(cc, out var country))
            {
                locale.Country = country;
            }
        }
    }
}
